## 5. 설정 코드

### 5.1 Redis 설정

```kotlin
// infrastructure/src/main/kotlin/com/maum/backend/config/RedisConfig.kt
@Configuration
class RedisConfig {
    @Bean
    fun redisTemplate(connectionFactory: RedisConnectionFactory): RedisTemplate<String, String> {
        return RedisTemplate<String, String>().apply {
            this.connectionFactory = connectionFactory
            keySerializer = StringRedisSerializer()
            valueSerializer = StringRedisSerializer()
            hashKeySerializer = StringRedisSerializer()
            hashValueSerializer = StringRedisSerializer()
        }
    }

    @Bean
    fun redissonClient(@Value("\${spring.redis.host}") host: String,
                       @Value("\${spring.redis.port}") port: Int): RedissonClient {
        val config = Config()
        config.useSingleServer().address = "redis://$host:$port"
        return Redisson.create(config)
