## 7. 캐시 무효화 전략

```kotlin
// 프로필 변경 시 캐시 무효화
@Service
class UserProfileService(
    private val userProfileCacheService: UserProfileCacheService,
    private val userProfileRepository: UserProfileRepository,
) {
    @Transactional
    fun updateProfile(userId: String, request: UpdateProfileRequest): UserProfileEntity {
        val profile = userProfileRepository.findByUserId(userId)
            ?: throw NotFoundException("프로필을 찾을 수 없습니다")

        val updated = userProfileRepository.save(profile.copy(age = request.age, ...))

        // 캐시 즉시 무효화 (Write-Through 방식)
        userProfileCacheService.invalidateProfileCache(userId)

        return updated
    }
}

// 차단 추가/해제 시 캐시 무효화
@Service
class BlockService(
    private val userProfileCacheService: UserProfileCacheService,
) {
    @Transactional
    fun blockUser(myUserId: String, targetUserId: String) {
        blockRepository.save(BlockEntity(userId = myUserId, targetUserId = targetUserId))
        // 차단 캐시 무효화
        userProfileCacheService.invalidateBlockedCache(myUserId)
    }
}
